<?php declare(strict_types=1); include_once "vision/vision.php"; $logDir = __DIR__ . '/Fondation/logs'; if (!is_dir($logDir)) { @mkdir($logDir, 0775, true); }
$logPath = $logDir . '/chat.log'; $cleanFile = $logDir . '/.clean_day'; $today = date('Ymd'); if (random_int(1, 100) === 1 || @file_get_contents($cleanFile) !== $today) { if (file_exists($logPath)) { $stats = stat($logPath); if ($stats['size'] > 32768 || (time() - $stats['mtime']) > 2592000) { file_put_contents($logPath, ""); } } $limit = time() - 2592000; $toDelete = Vision_API::find(fn($c) => ($c['data']['type'] ?? '') === 'chat_msg' && ($c['createdAt'] ?? 0) < $limit ); foreach ($toDelete as $cell) { Vision_API::delete($cell['id']); } Vision_API::clean(); file_put_contents($cleanFile, $today); }
function chat_log(string $message, string $path): void { $entry = sprintf("[%s] %s\n", date('Y-m-d H:i:s'), $message); @file_put_contents($path, $entry, FILE_APPEND | LOCK_EX); }
 $userFingerprint = hash('xxh64', $_SERVER['REMOTE_ADDR'] . ($_SERVER['HTTP_USER_AGENT'] ?? 'unknown')); $uid = $_COOKIE['chat_uid'] ?? ''; $currentCell = ($uid !== '') ? Vision_API::read($uid) : null; if ($currentCell && ($currentCell['data']['hash'] ?? '') !== $userFingerprint) $currentCell = null; if (!$currentCell) { $currentCell = Vision_API::find(fn($c) => ($c['data']['type'] ?? '') === 'chat_user' && ($c['data']['hash'] ?? '') === $userFingerprint)->current(); if ($currentCell) setcookie('chat_uid', $currentCell['id'], time() + 31536000, '/', '', true, true); } $configCell = Vision_API::find(fn($c) => ($c['data']['type'] ?? '') === 'chat_config')->current(); $adminCommand = (is_array($configCell) && isset($configCell['data']['admin_command'])) ? $configCell['data']['admin_command'] : "Gon🚀Kirua";  $isAdmin = false; $isBanned = false; $banMsg = "";  if (!$currentCell) {  $pseudo = "Bob " . bin2hex(random_bytes(2));  if (strtolower($pseudo) === 'iactu') { $pseudo = "Bob " . bin2hex(random_bytes(3)); } $userData = [ 'type' => 'chat_user', 'hash' => $userFingerprint, 'pseudo' => $pseudo, 'emoji' => '😊', 'ban_count' => 0, 'last_ban_at' => 0 ]; $userId = Vision_API::create($userData); setcookie('chat_uid', $userId, time() + 31536000, '/', '', true, true); $currentCell = ['id' => $userId, 'data' => $userData]; $currentPseudo = $pseudo; $currentEmoji = '😊'; $userHistory = []; $lastMsgTime = 0; chat_log("Nouveau profil créé : $currentPseudo", $logPath); } else { $currentPseudo = $currentCell['data']['pseudo']; $currentEmoji = $currentCell['data']['emoji'] ?? '😊'; $userId = $currentCell['id']; $userHistory = $currentCell['data']['msg_history'] ?? []; $lastMsgTime = $currentCell['data']['last_msg_t'] ?? 0; $isAdmin = (bool)($currentCell['data']['is_admin'] ?? false); $isBanned = ($currentCell['data']['banned_until'] ?? 0) > time();  if ($isAdmin) { $isBanned = false; }
$banMsg = ""; if ($isBanned) { $diff = $currentCell['data']['banned_until'] - time(); $h = floor($diff / 3600); $m = floor(($diff % 3600) / 60); if ($h >= 48) { $d = floor($h / 24); $banMsg = "Vous êtes banni. Temps restant : {$d} jours."; } else { $banMsg = "Vous êtes banni. Temps restant : {$h}h {$m}min."; } }
}  if (isset($_GET['action'])) { header('X-Content-Type-Options: nosniff'); header('Cache-Control: no-cache, no-store, must-revalidate'); header('Content-Type: application/json'); if ($_GET['action'] === 'get_messages') { $messages = Vision_API::find(fn($c) => ($c['data']['type'] ?? '') === 'chat_msg');  $all = iterator_to_array($messages, false); usort($all, fn($a, $b) => ($b['createdAt'] ?? 0) <=> ($a['createdAt'] ?? 0)); $last20 = array_slice($all, 0, 20);  echo json_encode([ 'messages' => $last20, 'user' => [ 'isAdmin' => $isAdmin, 'isBanned' => $isBanned, 'banMsg' => $banMsg ] ], JSON_THROW_ON_ERROR); exit; }
if ($_GET['action'] === 'send' && $_SERVER['REQUEST_METHOD'] === 'POST') {  if (!empty($_POST['valid_email_check'])) { chat_log("DETECTION: Bot (Honeypot) - IP: " . $_SERVER['REMOTE_ADDR'], $logPath); echo json_encode(['status' => 'error', 'msg' => 'Bot détecté (H)'], JSON_THROW_ON_ERROR); exit; }
 $loadTime = (int)($_POST['ts_load'] ?? 0); if ((time() - $loadTime) < 1 && !$isAdmin) { chat_log("DETECTION: Bot (Vitesse envoi) - IP: " . $_SERVER['REMOTE_ADDR'], $logPath); echo json_encode(['status' => 'error', 'msg' => 'Veuillez patienter 1s après le chargement.'], JSON_THROW_ON_ERROR); exit; }
 $pow = $_POST['pow'] ?? ''; if (!hash_equals(strrev(base64_encode($userFingerprint)), $pow)) { chat_log("DETECTION: Bot (PoW invalide) - IP: " . $_SERVER['REMOTE_ADDR'], $logPath); echo json_encode(['status' => 'error', 'msg' => 'Vérification de sécurité échouée.'], JSON_THROW_ON_ERROR); exit; }
 if ((time() - $lastMsgTime) < 2) { echo json_encode(['status' => 'error', 'msg' => 'Trop rapide ! (2s min)'], JSON_THROW_ON_ERROR); exit; }
 $now = time(); $userHistory = array_filter($userHistory, fn($t) => $t > ($now - 60)); if (count($userHistory) >= 5) { echo json_encode(['status' => 'error', 'msg' => 'Limite atteinte (5 msg/min)'], JSON_THROW_ON_ERROR); exit; }
 $rawText = $_POST['text'] ?? ''; $text = preg_replace_callback('/<(\/?)([a-z1-6]+)([^>]*)>/i', function($m) { $allowed = ['b','i','u','s','span','div','br','p','font','strong','em','strike']; $tag = strtolower($m[2]); if (!in_array($tag, $allowed)) return ''; if ($m[1] === '/') return "</$tag>";  preg_match_all('/(class|style|color|size|align)\s*=\s*["\']([^"\']*)["\']/i', $m[3], $attrMatches, PREG_SET_ORDER); $attrs = ''; foreach ($attrMatches as $am) {  if (!preg_match('/javascript:|on\w+|data:|&|\\\/i', $am[2])) { $attrs .= " {$am[1]}=\"" . htmlspecialchars($am[2], ENT_QUOTES) . "\""; } } return "<$tag" . (empty($attrs) ? "" : $attrs) . ">"; }, $rawText); $text = mb_substr(trim($text), 0, 8192);    if (strip_tags($text) === $adminCommand) { $userData = array_merge($currentCell['data'], [ 'pseudo' => 'iActu', 'emoji' => '🚀', 'is_admin' => true, 'last_msg_t' => $now ]); Vision_API::update($userId, $userData); usleep(20000); Vision_API::clean(); chat_log("ADMIN: Promotion de $currentPseudo en tant qu'iActu.", $logPath); echo json_encode(['status' => 'admin_promoted'], JSON_THROW_ON_ERROR); exit; }
  if ($isAdmin && mb_strpos($text, "Plan🚀B:") === 0) { $newCmd = trim(mb_substr($text, 7));  if (mb_strlen($newCmd) >= 4) { $configData = ['type' => 'chat_config', 'admin_command' => $newCmd]; if ($configCell) { Vision_API::update($configCell['id'], $configData); } else { Vision_API::create($configData); }   $userData = $currentCell['data']; $userData['is_admin'] = false; Vision_API::update($userId, $userData); usleep(20000); Vision_API::clean(); chat_log("ADMIN: Commande secrète modifiée. Accès révoqué pour vérification.", $logPath); echo json_encode(['status' => 'admin_revoked', 'msg' => 'Commande mise à jour ! Reconnectez-vous avec le nouveau code.'], JSON_THROW_ON_ERROR); exit; } }
if ($text !== '') { Vision_API::create([ 'type' => 'chat_msg', 'pseudo' => $currentPseudo, 'emoji' => $currentEmoji, 'text' => $text, 'user_hash' => $userFingerprint ]);  $userHistory[] = $now; $userData = array_merge($currentCell['data'], [ 'msg_history' => $userHistory, 'last_msg_t' => $now ]); Vision_API::update($userId, $userData); usleep(10000); Vision_API::clean(); chat_log("Message de $currentPseudo envoyé.", $logPath); echo json_encode(['status' => 'ok'], JSON_THROW_ON_ERROR); }
exit; }
if ($_GET['action'] === 'update_pseudo' && $_SERVER['REQUEST_METHOD'] === 'POST') { $newPseudo = mb_substr(trim($_POST['pseudo'] ?? ''), 0, 16); if (strtolower($newPseudo) === 'iactu' && !$isAdmin) { echo json_encode(['status' => 'error', 'msg' => 'Pseudo réservé !'], JSON_THROW_ON_ERROR); exit; }
$newEmoji = mb_substr(trim($_POST['emoji'] ?? $currentEmoji), 0, 32);  if (mb_strlen($newPseudo) >= 4 && mb_strlen($newPseudo) <= 16) { $userData = array_merge($currentCell['data'], [ 'pseudo' => $newPseudo, 'emoji' => $newEmoji ]); Vision_API::update($userId, $userData); usleep(20000); Vision_API::clean(); chat_log("Pseudo changé : $currentPseudo -> $newPseudo", $logPath); echo json_encode(['status' => 'ok', 'new' => $newPseudo], JSON_THROW_ON_ERROR); } else { echo json_encode(['status' => 'error', 'msg' => '4-16 caractères requis'], JSON_THROW_ON_ERROR); }
exit; }
 if ($isAdmin && isset($_GET['msg_id'])) { $msgId = $_GET['msg_id']; $targetMsg = Vision_API::read($msgId); if ($_GET['action'] === 'delete_msg' && $targetMsg) { Vision_API::delete($msgId); usleep(20000); Vision_API::clean(); chat_log("ADMIN: Message $msgId supprimé par $currentPseudo", $logPath); echo json_encode(['status' => 'ok'], JSON_THROW_ON_ERROR); exit; } if ($_GET['action'] === 'ban_user' && $targetMsg) { $targetHash = $targetMsg['data']['user_hash'] ?? null; if (!$targetHash) { echo json_encode(['status' => 'error', 'msg' => 'Utilisateur introuvable'], JSON_THROW_ON_ERROR); exit; } $now = time(); $todayStart = strtotime('today midnight'); $users = iterator_to_array(Vision_API::find(fn($c) => ($c['data']['type'] ?? '') === 'chat_user' && ($c['data']['hash'] ?? '') === $targetHash)); $banned = false; $isMajorBan = false; foreach ($users as $u) { if ($u['data']['is_admin'] ?? false) { echo json_encode(['status' => 'error', 'msg' => 'Action impossible sur un admin.'], JSON_THROW_ON_ERROR); exit; } $uData = $u['data']; $lastBan = $uData['last_ban_at'] ?? 0; $banCount = $uData['ban_count'] ?? 0; $banCount = (($now - $lastBan) < 172800) ? ($banCount + 1) : 1; $isMajorBan = ($banCount >= 3); $uData['banned_until'] = $now + ($isMajorBan ? 2592000 : 86400); $uData['last_ban_at'] = $now; $uData['ban_count'] = $isMajorBan ? 0 : $banCount; Vision_API::update($u['id'], $uData); $banned = true; } if ($banned) { $msgsToDelete = Vision_API::find(fn($m) => ($m['data']['type'] ?? '') === 'chat_msg' && ($m['data']['user_hash'] ?? '') === $targetHash && ($isMajorBan || ($m['createdAt'] ?? 0) >= $todayStart) ); foreach ($msgsToDelete as $mt) Vision_API::delete($mt['id']); usleep(50000); Vision_API::clean(); } chat_log("ADMIN: Bannissement effectué pour le hash $targetHash", $logPath); echo json_encode(['status' => 'ok'], JSON_THROW_ON_ERROR); exit; } echo json_encode(['status' => 'error', 'msg' => 'Action ou message introuvable'], JSON_THROW_ON_ERROR); exit; }
